'use strict';

const fs = require('fs');
const path = require('path');

const API_URL = 'https://api.prembly.com/api/v1/checker-widget/sdk/sessions/';
const LOG_FILE = path.join(__dirname, 'output.log');

async function fetchSessions() {
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!apiKey) {
    throw new Error('PREMBLY_API_KEY environment variable is not set.');
  }

  const response = await fetch(API_URL, {
    method: 'GET',
    headers: {
      'x-api-key': apiKey,
      'Accept': 'application/json',
      'Content-Type': 'application/json',
    },
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(
      `HTTP ${response.status} ${response.statusText} — ${body}`
    );
  }

  return response.json();
}

function countSessions(data) {
  // The Prembly SDK sessions endpoint typically returns:
  //   { status: true, detail: [...] }   – array under a key
  //   or a plain array
  if (Array.isArray(data)) {
    return data.length;
  }

  // Look for the first array-valued property and use its length
  for (const value of Object.values(data)) {
    if (Array.isArray(value)) {
      return value.length;
    }
  }

  // Fallback: treat the whole response as a single session object
  return typeof data === 'object' && data !== null ? 1 : 0;
}

async function main() {
  const timestamp = new Date().toISOString();

  try {
    console.log(`[${timestamp}] Polling Prembly SDK sessions…`);

    const data = await fetchSessions();
    const total = countSessions(data);

    const logLine = `Total sessions: ${total}\n`;

    fs.writeFileSync(LOG_FILE, logLine, 'utf8');

    console.log(`[${timestamp}] ${logLine.trim()}`);
    console.log(`[${timestamp}] Result written to ${LOG_FILE}`);
  } catch (err) {
    const errorLine = `Error: ${err.message}\n`;

    fs.writeFileSync(LOG_FILE, errorLine, 'utf8');

    console.error(`[${timestamp}] ${errorLine.trim()}`);
    process.exit(1);
  }
}

main();
